struct Grid16lLine: Shape {
	func path(in rect: CGRect) -> Path {
		
		var path = Path()
		let frame: CGRect = rect.fitRect(ratio: 270.0 / 280.0)
		
			//// Bezier 33 Drawing
		path.move(to: CGPoint(x: frame.minX + 0.04336 * frame.width, y: frame.minY))
		path.addLine(to: CGPoint(x: frame.minX + 0.04336 * frame.width, y: frame.maxY))
		
			//// Bezier 34 Drawing
		path.move(to: CGPoint(x: frame.minX + 0.54790 * frame.width, y: frame.minY))
		path.addLine(to: CGPoint(x: frame.minX + 0.54790 * frame.width, y: frame.maxY))
		
		return path
	}
}
